ALTER TABLE perfumes ADD COLUMN slug VARCHAR(255) UNIQUE AFTER name;

-- Generar slugs automáticamente desde el nombre
UPDATE perfumes SET slug = LOWER(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(name, ' ', '-'), '.', ''), ',', ''), '(', ''), ')', ''), '''', ''));